#include <stdio.h>
#include <stdbool.h>

bool is_valid_sequence(int **threads, int *sequence, int n, int *thread_indices, int sequence_index) {
    if (sequence_index == n) return true;
    for (int i = 0; i < n; i++) {
        if (thread_indices[i] < threads[i][0]) {
            if (threads[i][thread_indices[i] + 1] == sequence[sequence_index]) {
                thread_indices[i]++;
                if (is_valid_sequence(threads, sequence, n, thread_indices, sequence_index + 1)) return true;
                thread_indices[i]--;
            }
        }
    }
    return false;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int **threads = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            int ai;
            scanf("%d", &ai);
            threads[i] = (int *)malloc((ai + 1) * sizeof(int));
            threads[i][0] = ai;
            for (int j = 1; j <= ai; j++) {
                scanf("%d", &threads[i][j]);
            }
        }
        int *sequence = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &sequence[i]);
        }
        int *thread_indices = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            thread_indices[i] = 0;
        }
        if (is_valid_sequence(threads, sequence, n, thread_indices, 0)) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
        for (int i = 0; i < n; i++) {
            free(threads[i]);
        }
        free(threads);
        free(sequence);
        free(thread_indices);
    }
    return 0;
}

