#include <iostream>
#include <vector>
using namespace std;

bool is_valid_sequence(vector<vector<int>> &threads, vector<int> &sequence, int sequence_index) {
    if (sequence_index == sequence.size()) return true;
    for (int i = 0; i < threads.size(); i++) {
        if (threads[i].size() > 1) {
            if (threads[i][1] == sequence[sequence_index]) {
                threads[i].erase(threads[i].begin() + 1);
                if (is_valid_sequence(threads, sequence, sequence_index + 1)) return true;
                threads[i].insert(threads[i].begin() + 1, sequence[sequence_index]);
            }
        }
    }
    return false;
}

