import java.util.Scanner;
public class Main {
    public static boolean isValidSequence(int[][] threads, int[] sequence, int sequenceIndex) {
        if (sequenceIndex == sequence.length) return true;
        for (int i = 0; i < threads.length; i++) {
            if (threads[i][0] > 0) {
                if (threads[i][1] == sequence[sequenceIndex]) {
                    threads[i][0]--;
                    if (isValidSequence(threads, sequence, sequenceIndex + 1)) return true;
                    threads[i][0]++;
                }
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[][] threads = new int[n][];
            for (int i = 0; i < n; i++) {
                int ai = scanner.nextInt();
                threads[i] = new int[ai + 1];
                threads[i][0] = ai;
                for (int j = 1; j <= ai; j++) {
                    threads[i][j] = scanner.nextInt();
                }
            }
            int[] sequence = new int[n];
            for (int i = 0; i < n; i++) {
                sequence[i] = scanner.nextInt();
            }
            if (isValidSequence(threads, sequence, 0)) {
                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }
}

